#include<bits/stdc++.h>
using namespace std;
string s;
long long a[100005];
int main()
{
	int n;
	cin>>n;
	cin>>s;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		if(i%2==0)a[i]=-a[i];
	}
	for(int i=n-1;i>=1;i--){
		a[i]+=a[i+1];
	}
	for(int i=1;i<=n;i++){
		cout<<char(((s[i-1]-'a'-a[i])%26+26)%26+'a');
	}
}
